message.content:
@startuml
skinparam ClassDiagram labelStyle "C"
skinparam ClassDiagram styleClass fill:#f0f0f0,stroke:#333,stroke-width:1px
skinparam ClassDiagram styleClassMember fill:#fff,stroke:#333,stroke-width:1px
skinparam ClassDiagram styleAssociation fill:#fff,stroke:#333,stroke-width:1px
skinparam ClassDiagram styleGeneralization fill:#fff,stroke:#333,stroke-width:1px

class BasicEmailContent {
    content : String
    BasicEmailContent(content : String)
    getContent() : String
}

class ExternalEmailContent {
    ExternalEmailContent(content : String)
    getContent() : String
    addDisclaimer(content : String) : String
}

class SecureEmailContent {
    SecureEmailContent(content : String)
    getContent() : String
    encrypt(content : String) : String
}

BasicEmailContent ..> ExternalEmailContent
BasicEmailContent ..> SecureEmailContent

@enduml
